import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.function.Consumer;
import java.util.function.Function;
import java.util.function.Predicate;
import java.util.function.Supplier;

public class LambdaExamples {
    public static void main(String[] args) {
        Predicate<String> longWord = s -> s.length() > 5;
        Function<Integer, Integer> square = n -> n * n;
        Consumer<String> printer = System.out::println;
        Supplier<Double> random = Math::random;

        System.out.println("'Java' is long? " + longWord.test("Java"));
        System.out.println("Square of 7: " + square.apply(7));
        System.out.print("Random: ");
        printer.accept(String.valueOf(random.get()));

        List<String> words = new ArrayList<>(List.of("Java", "Lambda", "Stream", "Optional"));
        words.removeIf(s -> s.length() <= 4);
        words.sort(Comparator.comparingInt(String::length));
        System.out.println("\nFiltered & sorted: " + words);
        words.forEach(System.out::println);
    }
}

