import java.util.Arrays;
import java.util.Comparator;
import java.util.List;
import java.util.stream.Collectors;

public class StreamExamples {
    record Employee(String name, String dept, double salary) {}

    public static void main(String[] args) {
        List<Integer> nums = Arrays.asList(3, 8, 2, 9, 4, 8, 1);

        List<Integer> evensSquared = nums.stream()
            .filter(n -> n % 2 == 0)
            .map(n -> n * n)
            .distinct()
            .sorted()
            .collect(Collectors.toList());
        System.out.println("Evens squared: " + evensSquared);

        int sum = nums.stream().reduce(0, Integer::sum);
        System.out.println("Sum: " + sum);
        System.out.println("Max: " + nums.stream().max(Comparator.naturalOrder()).orElse(0));

        List<Employee> staff = List.of(
            new Employee("Riya", "Engineering", 85000),
            new Employee("Arjun", "HR", 45000),
            new Employee("Meera", "Engineering", 92000)
        );

        List<String> highEarners = staff.stream()
            .filter(e -> e.salary() > 50000)
            .map(Employee::name)
            .collect(Collectors.toList());
        System.out.println("High earners: " + highEarners);

        System.out.println("Any > 90k? " + staff.stream().anyMatch(e -> e.salary() > 90000));
    }
}

