import java.util.HashMap;
import java.util.Map;
import java.util.Optional;

public class OptionalExamples {
    record User(int id, String name) {}

    private static final Map<Integer, User> USERS = new HashMap<>();

    static {
        USERS.put(1, new User(1, "Riya"));
        USERS.put(2, new User(2, "Arjun"));
    }

    static Optional<User> findUserById(int id) {
        return Optional.ofNullable(USERS.get(id));
    }

    public static void main(String[] args) {
        Optional<String> present = Optional.of("Hello");
        Optional<String> absent = Optional.empty();
        String maybe = null;
        Optional<String> nullable = Optional.ofNullable(maybe);

        present.ifPresent(v -> System.out.println("Present: " + v));
        System.out.println("Absent or default: " + absent.orElse("Guest"));
        System.out.println("Nullable: " + nullable.orElseGet(() -> "Generated default"));

        findUserById(1).ifPresent(u -> System.out.println("Found: " + u.name()));
        findUserById(99).ifPresentOrElse(
            u -> System.out.println("Found: " + u.name()),
            () -> System.out.println("User 99 not found.")
        );

        String upper = findUserById(1)
            .map(User::name)
            .map(String::toUpperCase)
            .orElse("UNKNOWN");
        System.out.println("Upper name: " + upper);
    }
}

