import java.time.Duration;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.LocalTime;
import java.time.Period;
import java.time.format.DateTimeFormatter;

public class DateTimeExamples {
    public static void main(String[] args) {
        LocalDate today = LocalDate.now();
        LocalDate exam = LocalDate.of(2025, 6, 15);
        System.out.println("Today: " + today);
        System.out.println("Exam: " + exam);
        System.out.println("Exam in " + Period.between(today, exam).getDays() + " days (approx)");

        LocalTime start = LocalTime.of(9, 0);
        LocalTime end = LocalTime.of(17, 30);
        Duration workDay = Duration.between(start, end);
        System.out.println("Work hours: " + workDay.toHours() + "h " + (workDay.toMinutesPart()) + "m");

        LocalDateTime meeting = LocalDateTime.of(exam, LocalTime.of(14, 30));
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("dd-MM-yyyy HH:mm");
        System.out.println("Meeting: " + meeting.format(fmt));

        LocalDate parsed = LocalDate.parse("20-06-2025",
            DateTimeFormatter.ofPattern("dd-MM-yyyy"));
        System.out.println("Parsed: " + parsed.plusDays(7));
    }
}

