public class ThreadExamples {
    static class CounterThread extends Thread {
        private final String label;
        CounterThread(String label) { this.label = label; }
        @Override public void run() {
            for (int i = 1; i <= 5; i++) {
                System.out.println(label + " [" + getName() + "]: " + i);
                try { Thread.sleep(200); } catch (InterruptedException e) { return; }
            }
        }
    }

    public static void main(String[] args) throws InterruptedException {
        Thread t1 = new CounterThread("Worker-A");
        Thread t2 = new Thread(() -> {
            for (int i = 1; i <= 3; i++) {
                System.out.println("Runnable-B [" + Thread.currentThread().getName() + "]: " + i);
            }
        });

        t1.start();
        t2.start();
        t1.join();
        t2.join();
        System.out.println("Main: all workers finished.");
    }
}

