import java.time.LocalDate;
import java.util.Comparator;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.stream.Collectors;

public class EmployeeAnalytics {
    record Employee(int id, String name, String dept, double salary, LocalDate joined) {}

    private final List<Employee> staff = List.of(
        new Employee(1, "Riya", "Engineering", 85000, LocalDate.of(2022, 3, 1)),
        new Employee(2, "Arjun", "HR", 55000, LocalDate.of(2021, 6, 15)),
        new Employee(3, "Meera", "Engineering", 92000, LocalDate.of(2020, 1, 10)),
        new Employee(4, "Kiran", "Sales", 60000, LocalDate.of(2023, 8, 20)),
        new Employee(5, "Sneha", "Engineering", 78000, LocalDate.of(2022, 11, 5)),
        new Employee(6, "Vikram", "Sales", 65000, LocalDate.of(2021, 4, 12))
    );

    Optional<Employee> findByName(String name) {
        return staff.stream().filter(e -> e.name().equalsIgnoreCase(name)).findFirst();
    }

    public static void main(String[] args) {
        EmployeeAnalytics analytics = new EmployeeAnalytics();

        Map<String, Double> avgByDept = analytics.staff.stream()
            .collect(Collectors.groupingBy(Employee::dept, Collectors.averagingDouble(Employee::salary)));
        System.out.println("Avg salary by dept: " + avgByDept);

        System.out.println("\nTop 3 earners:");
        analytics.staff.stream()
            .sorted(Comparator.comparingDouble(Employee::salary).reversed())
            .limit(3)
            .forEach(System.out::println);

        analytics.findByName("Meera").ifPresent(e ->
            System.out.println("\nFound: " + e.name() + ", Rs." + e.salary()));
    }
}

