import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;

public class TicketBookingSystem {
    static class TicketCounter {
        private int availableSeats;

        TicketCounter(int seats) { this.availableSeats = seats; }

        synchronized boolean bookSeat(String user) {
            if (availableSeats <= 0) {
                System.out.println(user + ": Sold out!");
                return false;
            }
            availableSeats--;
            System.out.println(user + " booked. Remaining: " + availableSeats);
            return true;
        }
    }

    public static void main(String[] args) throws InterruptedException {
        TicketCounter counter = new TicketCounter(5);
        ExecutorService pool = Executors.newFixedThreadPool(8);

        for (int i = 1; i <= 10; i++) {
            String user = "User-" + i;
            pool.execute(() -> counter.bookSeat(user));
        }

        pool.shutdown();
        pool.awaitTermination(5, TimeUnit.SECONDS);
    }
}

