import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

public class TaskScheduler {
    static void runTask(String name) {
        System.out.println("[" + name + "] RUNNING on " + Thread.currentThread().getName());
        try { Thread.sleep(500); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        System.out.println("[" + name + "] COMPLETED");
    }

    public static void main(String[] args) throws InterruptedException {
        ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(2);

        System.out.println("Scheduling one-time backup in 2 seconds...");
        scheduler.schedule(() -> runTask("Backup"), 2, TimeUnit.SECONDS);

        System.out.println("Scheduling health-check every 1 second (3 runs)...");
        final int[] count = {0};
        scheduler.scheduleAtFixedRate(() -> {
            count[0]++;
            runTask("HealthCheck-" + count[0]);
            if (count[0] >= 3) scheduler.shutdown();
        }, 1, 1, TimeUnit.SECONDS);

        scheduler.awaitTermination(10, TimeUnit.SECONDS);
        System.out.println("Scheduler shut down.");
    }
}
